import java.util.regex.*;
public class FindAll {
    public static void main(String[] args) {
        Matcher m = Pattern.compile("\\d+").matcher("a1b22c333");
        int count = 0;
        while (m.find()) count++;
        System.out.println(count);
        m.reset();
        m.find();
        System.out.println(m.group());
